def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def check_no_solution(nums, target):
    if not nums:
        return True  # No solution if the list is empty
    return False

def check_indices_not_reused(left, right):
    return left != right

# Example usage
def find_indices(nums, target):
    if check_no_solution(nums, target):
        return -1, -1
    left, right = solve(nums, target)
    if not check_indices_not_reused(left, right):
        return -1, -1
    return left, right
